form:Form.form:Scripts:
		function ToList()
{	
	Ctrl("LISTA").DoEvent("showList");
}

function nombreyapellido ()
{
	Ctrl('d_apellido').SetXValue(Trim(Ctrl('d_apellido').GetXValue()));
	Ctrl('d_nombres').SetXValue(Trim(Ctrl('d_nombres').GetXValue()));
	Ctrl('d_ape_y_nom').SetCValue(Ctrl('d_apellido').GetCValue()+', '+Ctrl('d_nombres').GetCValue());		
}



function codigo()
{
	var mp, nSQL, docPar;
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();  
	docPar = nSQL.GetOBJ(Ctrl("main").getResource("qry:TIPODOC"), "<PARAM id=\""+Ctrl("oi_tipo_documento").GetXValue()+"\" />");	
	Ctrl('c_tercero').SetCValue(docPar.cod.toString()+Ctrl('c_documento').GetCValue());		
}
